/**
 * Atlas OTP Input
 * 
 * High-fidelity logic for grouped OTP (One-Time Password) boxes.
 * Handles auto-focus, digit-only restriction, and paste support.
 */

export class OtpInput {
  constructor(container) {
    if (!container) return;
    this.container = typeof container === 'string' ? document.querySelector(container) : container;
    
    // Guard against double-initialization
    if (this.container.__atlas_init) return this.container.__atlas_instance;
    this.container.__atlas_init = true;

    this.inputs = Array.from(this.container.querySelectorAll('.otp-input-box'));
    if (this.inputs.length === 0) return;

    this.fieldContainer = this.container.closest('.otp-field');
    this.callbacks = { change: [] };

    this.init();
    this.container.__atlas_instance = this;
    
    // Explicitly reset on start to prevent browser cache issues
    this.reset();
  }

  init() {
    this.inputs.forEach((input, index) => {
      // Direct selection on focus
      input.addEventListener('focus', () => input.select());
      input.addEventListener('click', () => input.select());

      // Auto-focus logic
      input.addEventListener('input', (e) => {
        const val = e.target.value;
        
        // Sanitize to digits only
        if (input.getAttribute('inputmode') === 'numeric' || input.type === 'number') {
          e.target.value = val.replace(/[^0-9]/g, '').slice(-1);
        }

        this.setError(false); // Clear error on type

        if (e.target.value && index < this.inputs.length - 1) {
          this.inputs[index + 1].focus();
        }
        
        this.dispatch();
      });

      // Navigation & Backspace
      input.addEventListener('keydown', (e) => {
        if (e.key === 'Backspace' && !input.value && index > 0) {
          this.inputs[index - 1].focus();
        } else if (e.key === 'ArrowLeft' && index > 0) {
          this.inputs[index - 1].focus();
        } else if (e.key === 'ArrowRight' && index < this.inputs.length - 1) {
          this.inputs[index + 1].focus();
        }
      });

      // Paste Support
      input.addEventListener('paste', (e) => {
        e.preventDefault();
        const pastedData = e.clipboardData.getData('text').replace(/[^0-9]/g, '');
        if (!pastedData) return;

        this.setError(false);

        // Distribute characters starting from the current input
        pastedData.split('').forEach((char, i) => {
          const targetInput = this.inputs[index + i];
          if (targetInput) {
            targetInput.value = char;
          }
        });

        // Focus the next empty input or the last one filled
        const lastFilledIndex = Math.min(index + pastedData.length, this.inputs.length - 1);
        this.inputs[lastFilledIndex].focus();
        
        this.dispatch();
      });
    });
  }

  get value() {
    return this.inputs.map(i => i.value).join('');
  }

  set value(newValue) {
    const chars = String(newValue).split('');
    this.inputs.forEach((input, i) => {
      input.value = chars[i] || '';
    });
    this.setError(false);
    this.dispatch();
  }

  setError(hasError) {
    if (this.fieldContainer) {
      this.fieldContainer.classList.toggle('is-error', !!hasError);
    }
  }

  validate() {
    const isComplete = this.value.length === this.inputs.length;
    this.setError(!isComplete);
    return isComplete;
  }

  reset() {
    this.inputs.forEach(i => i.value = '');
    this.setError(false);
  }

  on(event, callback) {
    if (this.callbacks[event]) {
      this.callbacks[event].push(callback);
    }
    return this;
  }

  dispatch() {
    const val = this.value;
    const isComplete = val.length === this.inputs.length;

    // Better DX Callbacks
    this.callbacks.change.forEach(cb => cb(val, isComplete));

    // data-attribute sync
    this.container.setAttribute('data-otp-value', val);

    // Standard DOM Event
    const event = new CustomEvent('otp-change', { 
      detail: { value: val, isComplete } 
    });
    this.container.dispatchEvent(event);
  }
}

/**
 * Factory initialization
 */
export function initOtpInput(element) {
  return new OtpInput(element);
}
